-- ---------------------------------------------------------------------
-- 7) French translations (language_id resolved as @lang_fr above).
--    Each page is matched by its English slug so it is robust to id drift.
--    Delete-then-insert the French row so it OVERWRITES any stale same-id
--    content (e.g. leftover Romanian demo rows that occupied language_id 2
--    before French was installed). Idempotent; skipped if French is absent.
-- ---------------------------------------------------------------------
-- Remove leftover Romanian demo rows that may occupy @lang_fr (these shipped
-- with Vvveb at language_id 2; if French was installed as id 2 they masquerade
-- as French). Matched by their distinctive Romanian slugs so real content is untouched.
DELETE FROM post_content WHERE @lang_fr IS NOT NULL AND language_id = @lang_fr
  AND slug IN ('buna-lume-1','buna-lume-2','buna-lume-3','buna-lume-4','buna-lume-5','buna-lume-6',
               'despre','servicii','livrare','termeni-conditii','politica-confidentialitate',
               'preturi','portfoliu','piata','politica-subscriptii');
