INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Solutions', 'solutions', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Nos solutions</span><h2>Une approche complète de la <span class="sd-gradient-text">souveraineté</span></h2><p class="section-lead">De l\'évaluation initiale au déploiement opérationnel, nos experts couvrent l\'ensemble du cycle de vie de votre stratégie de souveraineté numérique.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M18 10h-1.26A8 8 0 109 20h9a5 5 0 000-10z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/></svg></div><h3>Cloud Souverain</h3><p>Migration et hébergement sur une infrastructure européenne certifiée, avec une protection garantie contre les lois extraterritoriales.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon sd-card-icon-accent"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><rect x="3" y="11" width="18" height="11" rx="2" stroke="currentColor" stroke-width="2"/><path d="M7 11V7a5 5 0 0110 0v4" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg></div><h3>Protection des Données</h3><p>Chiffrement de bout en bout, gestion souveraine des clés (HSM, KMS) et politiques de conservation conformes au RGPD.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon sd-card-icon-orange"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M9 12l2 2 4-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h3>Conformité &amp; Audit</h3><p>Audits SecNumCloud, ISO 27001, HDS et NIS2. Un accompagnement complet sur les référentiels nationaux et européens.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="10" stroke="currentColor" stroke-width="2"/><path d="M2 12h20M12 2a14 14 0 010 20M12 2a14 14 0 000 20" stroke="currentColor" stroke-width="2"/></svg></div><h3>Cybersécurité &amp; SOC</h3><p>Détection des menaces 24/7, SOC souverain infogéré et tests d\'intrusion adaptés à vos charges critiques.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon sd-card-icon-accent"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M14 2v6h6M9 13h6M9 17h6" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg></div><h3>Stratégie &amp; Conseil</h3><p>Cartographie des dépendances, analyse des risques et feuille de route de souveraineté pluriannuelle conçue pour votre DSI.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><div class="sd-card-icon sd-card-icon-orange"><svg width="26" height="26" viewBox="0 0 24 24" fill="none"><path d="M22 10v6M2 10l10-5 10 5-10 5z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M6 12v5c3 3 9 3 12 0v-5" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/></svg></div><h3>Formation des Équipes</h3><p>Sessions de sensibilisation, ateliers et certifications pour ancrer la souveraineté dans votre culture.</p><a href="/fr/page/contact" class="sd-card-link">En savoir plus <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div></div></div>', '', 'solutions, cloud souverain, protection des données, cybersécurité, conformité, conseil, formation', 'Cloud souverain, protection des données, cybersécurité, conformité, conseil et formation pour les organisations européennes.'
