INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Méthode & Certifications', 'certifications', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Notre méthode</span><h2>Un parcours clair en <span class="sd-gradient-text">4 étapes</span></h2><p class="section-lead">De la première analyse à la mise en production, nous suivons une méthode éprouvée auprès de plus de 250 organisations européennes.</p></div><div class="row g-4"><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">01</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><circle cx="11" cy="11" r="7" stroke="currentColor" stroke-width="2"/><path d="M21 21l-4.35-4.35" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg></div><h3>Audit &amp; Cartographie</h3><p>Nous cartographions vos données, vos charges et votre exposition réglementaire pour identifier ce qui requiert réellement la souveraineté.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">02</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M14 2v6h6" stroke="currentColor" stroke-width="2"/></svg></div><h3>Stratégie sur Mesure</h3><p>Une feuille de route alignée sur les contraintes de votre secteur, votre budget et vos outils existants.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">03</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M12 2v4M12 18v4M2 12h4M18 12h4M5 5l3 3M16 16l3 3M19 5l-3 3M8 16l-3 3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><circle cx="12" cy="12" r="3" stroke="currentColor" stroke-width="2"/></svg></div><h3>Mise en Œuvre</h3><p>Migration et intégration avec réversibilité garantie et sans verrouillage caché.</p></div></div><div class="col-md-6 col-lg-3"><div class="sd-step"><div class="sd-step-number">04</div><div class="sd-step-icon"><svg width="22" height="22" viewBox="0 0 24 24" fill="none"><path d="M3 12a9 9 0 1015.5-6.3" stroke="currentColor" stroke-width="2" stroke-linecap="round"/><path d="M18 3v4h-4" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h3>Exploitation &amp; Amélioration</h3><p>Supervision continue, optimisation et support 24/7 assurés par nos équipes européennes.</p></div></div></div><div class="sd-section-header" style="margin-top:4rem;"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Certifications</span><h2>Des standards reconnus, audités et <span class="sd-gradient-text">vérifiables</span></h2><p class="section-lead">Nous opérons selon les référentiels les plus exigeants. Chacun de nos services est certifié par des auditeurs indépendants accrédités.</p></div><div class="row g-3 g-md-4"><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M9 12l2 2 4-4" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h4>SecNumCloud</h4><p>ANSSI 3.2</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="2"/><text x="12" y="15" text-anchor="middle" font-size="6" font-weight="700" fill="currentColor">ISO</text></svg></div><h4>ISO 27001</h4><p>Management SSI</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M12 3l2.5 5 5.5.8-4 3.9 1 5.5-5-2.6-5 2.6 1-5.5-4-3.9 5.5-.8z" stroke="currentColor" stroke-width="1.8" stroke-linejoin="round"/></svg></div><h4>HDS</h4><p>Données de santé</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><rect x="4" y="9" width="16" height="12" rx="2" stroke="currentColor" stroke-width="2"/><path d="M8 9V6a4 4 0 018 0v3" stroke="currentColor" stroke-width="2"/></svg></div><h4>RGPD</h4><p>Conformité UE</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="12" r="9" stroke="currentColor" stroke-width="2"/><path d="M3 12h18M12 3a14 14 0 010 18M12 3a14 14 0 000 18" stroke="currentColor" stroke-width="1.5"/></svg></div><h4>NIS2</h4><p>Directive UE</p></div></div><div class="col-6 col-md-4 col-lg-2"><div class="sd-cert-card"><div class="sd-cert-badge"><svg width="34" height="34" viewBox="0 0 24 24" fill="none"><path d="M5 7l7-4 7 4v6c0 5-3.5 7.5-7 9-3.5-1.5-7-4-7-9z" stroke="currentColor" stroke-width="2" stroke-linejoin="round"/><path d="M12 8v4l2 2" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg></div><h4>SOC 2</h4><p>Type II</p></div></div></div><div class="row g-4" style="margin-top:3.5rem;"><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">250+</div><div class="sd-stat-label">Organisations accompagnées</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">99.99%</div><div class="sd-stat-label">Disponibilité SLA moyenne</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">14</div><div class="sd-stat-label">Pays européens</div></div></div><div class="col-6 col-md-3"><div class="sd-stat"><div class="sd-stat-number">24/7</div><div class="sd-stat-label">SOC souverain</div></div></div></div>', '', 'méthode, certifications, SecNumCloud, ISO 27001, HDS, RGPD, NIS2, SOC 2', 'Notre méthode éprouvée en 4 étapes et les certifications reconnues (SecNumCloud, ISO 27001, HDS, RGPD, NIS2, SOC 2) qui sous-tendent nos solutions souveraines.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL;

-- Cloud Souverain
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'sovereign-cloud' AND language_id = @lang ORDER BY post_id LIMIT 1);
DELETE FROM post_content WHERE @pid IS NOT NULL AND @lang_fr IS NOT NULL AND post_id = @pid AND language_id = @lang_fr;
INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Cloud Souverain', 'cloud-souverain', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Cloud Souverain</span><h2>Hébergement cloud européen, <span class="sd-gradient-text">à l\'abri des lois extraterritoriales</span></h2><p class="section-lead">Migrez et exploitez vos charges sur une infrastructure européenne certifiée (SecNumCloud, ISO 27001, HDS). Gardez le contrôle total de l\'emplacement de vos données, de qui y accède et de la façon dont elles sont exploitées &mdash; sans exposition au CLOUD Act américain ni à d\'autres juridictions étrangères.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Infrastructure UE certifiée</h3><p>Datacenters exploités au sein de l\'Union européenne sous SecNumCloud 3.2 et ISO 27001, avec des garanties contractuelles contre l\'accès extraterritorial.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Migration fluide</h3><p>Migration à l\'identique ou re-plateformage de vos VM, conteneurs et bases de données, avec des bascules sans interruption et un retour arrière sécurisé.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Réversibilité garantie</h3><p>Standards ouverts et formats portables : vous pouvez partir à tout moment &mdash; sans verrouillage propriétaire ni frais de sortie cachés.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Élastique &amp; performant</h3><p>Calcul auto-scalable, stockage objet souverain et Kubernetes infogéré, à la hauteur des hyperscalers sans le risque juridictionnel.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>SLA 99,99 %</h3><p>Résilience multi-zone, sauvegardes automatisées et supervision 24/7 par des équipes européennes, adossées à un engagement contractuel de disponibilité.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Tarification transparente</h3><p>Facturation prévisible en euros, sans frais de sortie surprises &mdash; budgétez votre cloud souverain en toute confiance.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">Des organisations du secteur public, de la santé, de la finance et de la défense, dans 14 pays européens, confient à notre cloud souverain leurs charges les plus sensibles. Prêt à évaluer votre migration ?</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Parler à un expert cloud souverain <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'cloud souverain, cloud européen, SecNumCloud, hébergement RGPD, souveraineté des données, ISO 27001', 'Hébergement cloud souverain sur infrastructure européenne certifiée (SecNumCloud, ISO 27001). Contrôle total des données, protection extraterritoriale et réversibilité garantie.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL;

-- Protection des Données
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'data-protection' AND language_id = @lang ORDER BY post_id LIMIT 1);
DELETE FROM post_content WHERE @pid IS NOT NULL AND @lang_fr IS NOT NULL AND post_id = @pid AND language_id = @lang_fr;
INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Protection des Données', 'protection-donnees', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Protection des Données</span><h2>Chiffrement, souveraineté des clés et <span class="sd-gradient-text">RGPD by design</span></h2><p class="section-lead">Protégez vos données personnelles et stratégiques de bout en bout grâce au chiffrement souverain, à la gestion matérielle des clés et à des politiques de conservation conçues pour le RGPD. Vos clés, votre contrôle &mdash; même votre fournisseur cloud ne peut lire vos données.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Chiffrement de bout en bout</h3><p>Données chiffrées en transit et au repos avec des algorithmes robustes et audités &mdash; pour vous protéger des fuites et des accès non autorisés.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Gestion souveraine des clés</h3><p>Détenez et faites tourner vos propres clés avec HSM et KMS hébergés en Europe. BYOK (apportez votre clé) et HYOK (gardez votre clé) pris en charge.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Conservation conforme au RGPD</h3><p>Conservation, minimisation et droit à l\'effacement automatisés, pour rester conforme sans effort manuel.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Classification des données</h3><p>Découvrez, étiquetez et gouvernez les données sensibles de tout votre patrimoine pour que les bons contrôles suivent automatiquement la donnée.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Sauvegarde &amp; restauration</h3><p>Sauvegardes immuables et géo-redondantes en Europe, avec procédures de restauration testées et instantanés résistants aux rançongiciels.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Gouvernance des accès</h3><p>Accès au moindre privilège, journaux d\'audit complets et élévation à la demande pour prouver qui a accédé à quoi, et quand.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">Faites du RGPD un avantage concurrentiel plutôt qu\'une contrainte. Laissez-nous évaluer votre posture de protection des données et combler les écarts.</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Demander un audit de protection des données <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'protection des données, conformité RGPD, chiffrement, gestion des clés, HSM, KMS, souveraineté des données', 'Chiffrement de bout en bout, gestion souveraine des clés (HSM/KMS) et conservation conforme au RGPD. Protégez vos données avec des clés que vous contrôlez, hébergées en Europe.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL;

-- Cybersécurité & SOC
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'cybersecurity-soc' AND language_id = @lang ORDER BY post_id LIMIT 1);
DELETE FROM post_content WHERE @pid IS NOT NULL AND @lang_fr IS NOT NULL AND post_id = @pid AND language_id = @lang_fr;
INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Cybersécurité & SOC', 'cybersecurite-soc', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Cybersécurité &amp; SOC</span><h2>Détection des menaces 24/7 depuis un <span class="sd-gradient-text">SOC souverain</span></h2><p class="section-lead">Un centre des opérations de sécurité (SOC) européen infogéré qui surveille vos charges critiques en continu. Détectez, investiguez et répondez aux menaces plus vite &mdash; avec analystes, outils et données conservés en Europe.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>SOC infogéré 24/7</h3><p>Des analystes européens surveillent votre environnement jour et nuit, trient les alertes et escaladent les vrais incidents en quelques minutes.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Détection &amp; réponse aux menaces</h3><p>SIEM, EDR et renseignement sur les menaces réunis dans un service de détection et réponse gérées (MDR) calibré sur votre profil de risque.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Tests d\'intrusion</h3><p>Missions de sécurité offensive et exercices red-team qui révèlent les failles avant les attaquants.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Réponse à incident</h3><p>Un plan d\'action éprouvé et des experts d\'astreinte pour contenir, éradiquer et se relever des incidents avec un impact minimal.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Gestion des vulnérabilités</h3><p>Analyse continue, priorisation et suivi de la remédiation sur l\'ensemble de vos applications et infrastructures.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Préparation NIS2</h3><p>Contrôles, reporting et gouvernance alignés sur la directive NIS2 pour les entités essentielles et importantes.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">Les attaquants n\'ont pas d\'horaires de bureau &mdash; nous non plus. Découvrez comment un SOC souverain renforce votre défense.</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Réserver une consultation SOC <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'cybersécurité, SOC infogéré, MDR, détection des menaces, test d\'intrusion, réponse à incident, NIS2', 'SOC souverain infogéré 24/7 : détection et réponse aux menaces, tests d\'intrusion, réponse à incident et préparation NIS2 pour vos charges critiques européennes.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL;

-- Conformité & Audit
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'compliance-audit' AND language_id = @lang ORDER BY post_id LIMIT 1);
DELETE FROM post_content WHERE @pid IS NOT NULL AND @lang_fr IS NOT NULL AND post_id = @pid AND language_id = @lang_fr;
INSERT INTO post_content (post_id, language_id, name, slug, content, excerpt, meta_keywords, meta_description)
SELECT @pid, @lang_fr, 'Conformité & Audit', 'conformite-audit', '<div class="sd-section-header"><span class="sd-eyebrow"><span class="sd-eyebrow-dot"></span>Conformité &amp; Audit</span><h2>Réussissez chaque audit, sur <span class="sd-gradient-text">tous les référentiels</span></h2><p class="section-lead">De SecNumCloud et ISO 27001 à HDS, au RGPD et à NIS2, nous vous guidons dans la préparation, la collecte de preuves et la certification &mdash; transformant la conformité d\'une course récurrente en un processus répétable et prêt pour l\'audit.</p></div><div class="row g-4"><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>SecNumCloud</h3><p>Préparation ANSSI 3.2 et accompagnement à la qualification, le plus haut standard de confiance cloud français et européen.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>ISO 27001</h3><p>Construisez et certifiez un système de management de la sécurité de l\'information auquel auditeurs et clients font confiance.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>HDS</h3><p>Certification Hébergeur de Données de Santé pour les organisations traitant des données patients et médicales sensibles.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Audit RGPD</h3><p>Analyse d\'écarts, registre des traitements et appui aux AIPD pour démontrer votre responsabilité au titre du RGPD.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Directive NIS2</h3><p>Cartographiez les obligations, comblez les écarts et préparez la gouvernance et le reporting exigés par NIS2.</p></div></div><div class="col-md-6 col-lg-4"><div class="sd-card"><h3>Conformité continue</h3><p>Collecte de preuves et surveillance des contrôles automatisées pour rester prêt pour l\'audit toute l\'année.</p></div></div></div><div class="sd-section-header" style="margin-top:3rem;"><p class="section-lead">Ne redoutez plus la saison des audits. Nos experts accrédités font de la conformité une discipline continue et peu contraignante.</p><a href="/fr/page/contact" class="sd-btn sd-btn-primary">Planifier une évaluation de conformité <svg width="14" height="14" viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 5l7 7-7 7" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg></a></div>', '', 'conformité, audit, SecNumCloud, ISO 27001, HDS, RGPD, NIS2, certification', 'Accompagnement à la préparation et à la certification sur SecNumCloud, ISO 27001, HDS, RGPD et NIS2. Faites de la conformité un processus répétable et continu.'
WHERE @lang_fr IS NOT NULL AND @pid IS NOT NULL;

-- Stratégie & Conseil
SET @pid := (SELECT post_id FROM post_content WHERE slug = 'strategy-consulting' AND language_id = @lang ORDER BY post_id LIMIT 1);
